import json

def parse_config_json(config_json_string):
  """
  Parses a JSON string representing a configuration file and returns the 'database' section as a dictionary.

  Args:
    config_json_string: A string containing the JSON data.

  Returns:
    A dictionary representing the 'database' section of the JSON data, 
    or None if the 'database' section is not found or the input is invalid JSON.
  """
  try:
    config_data = json.loads(config_json_string)
    if 'database' in config_data:
      return config_data['database']
    else:
      return None  # 'database' section not found
  except json.JSONDecodeError:
    return None  # Invalid JSON input


