import json

def convert_snake_to_camel(json_file_path, output_file_path):
    """
    Converts snake_case keys in a JSON file to camelCase and saves the result.

    Args:
        json_file_path: The path to the input JSON file.
        output_file_path: The path to the output JSON file.
    """

    try:
        with open(json_file_path, 'r') as f:
            data = json.load(f)

        def to_camel_case(key):
            components = key.split('_')
            return components[0] + ''.join(x.title() for x in components[1:])

        def convert_keys(obj):
            if isinstance(obj, dict):
                new_obj = {}
                for k, v in obj.items():
                    new_k = to_camel_case(k)
                    new_obj[new_k] = convert_keys(v)
                return new_obj
            elif isinstance(obj, list):
                return [convert_keys(item) for item in obj]
            else:
                return obj

        converted_data = convert_keys(data)

        with open(output_file_path, 'w') as f:
            json.dump(converted_data, f, indent=4)  # Use indent for readability

        print(f"Successfully converted snake_case to camelCase and saved to {output_file_path}")

    except FileNotFoundError:
        print(f"Error: File not found at {json_file_path}")
    except json.JSONDecodeError:
        print(f"Error: Invalid JSON format in {json_file_path}")
    except Exception as e:
        print(f"An error occurred: {e}")


